challenges.test_code:
assert score == 85, 'score should remain 85'
assert grade == 'B', f'Expected grade B for score 85, got {grade}'

# Test other scores by re-running the logic
for test_score, expected in [(95, 'A'), (90, 'A'), (85, 'B'), (80, 'B'), (75, 'C'), (70, 'C'), (65, 'D'), (60, 'D'), (55, 'F'), (0, 'F')]:
    score = test_score
    if score >= 90:
        grade = 'A'
    elif score >= 80:
        grade = 'B'
    elif score >= 70:
        grade = 'C'
    elif score >= 60:
        grade = 'D'
    else:
        grade = 'F'
    assert grade == expected, f'For score {test_score}, expected {expected} but got {grade}'
